"use client";

import { useEffect, useRef, useState, useCallback } from "react";
 
// ─── Butterfly cursor frames (extracted from .ani file, 128×128 px each) ───
// 8 frames @ ~83 ms/frame (5 jiffies × 1/60 s)
const FRAMES = [
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,"
];
 
const FRAME_DURATION = 83; // ms per frame
const CURSOR_SIZE = 64;    // px — adjust to taste (original is 128 px)
const HOT_SPOT_X = 0;      // px from left of image
const HOT_SPOT_Y = 0;      // px from top of image
 
/**
 * ButterflyAnimatedCursor
 *
 * Drop this component once inside your React app root (e.g. App.jsx).
 * It hides the default cursor across the whole page and renders the animated
 * orange-butterfly cursor as an absolutely-positioned <img> that follows the
 * mouse in real time.
 *
 * No external dependencies — pure React hooks + CSS.
 */
export default function CustomCursor() {
  const posRef    = useRef({ x: -200, y: -200 });
  const frameRef  = useRef(0);
  const rafRef    = useRef<number | null>(null);
  const lastRef   = useRef<number | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [visible, setVisible] = useState(false);
  const [isTouchDevice, setIsTouchDevice] = useState(true); // Assume true initially for SSR safety, or false. Better: false initially, check in effect.

  useEffect(() => {
    if (typeof window !== "undefined") {
      setIsTouchDevice('ontouchstart' in window || navigator.maxTouchPoints > 0);
    }
  }, []);
 
  // Throttled mouse-move: store position in a ref (no re-render)
  const onMouseMove = useCallback((e: MouseEvent) => {
    posRef.current = { x: e.clientX, y: e.clientY };
    if (!visible) setVisible(true);
  }, [visible]);
 
  const onMouseLeave = useCallback(() => setVisible(false), []);
 
  useEffect(() => {
    if (isTouchDevice) return;

    // Inject global styles to replace the default arrow cursor with a tiny flower
    const style = document.createElement("style");
    const flowerSvg = `data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3" fill="%23F9C846"/><circle cx="12" cy="6" r="4" fill="%23F06292"/><circle cx="12" cy="18" r="4" fill="%23F06292"/><circle cx="6" cy="12" r="4" fill="%23F06292"/><circle cx="18" cy="12" r="4" fill="%23F06292"/></svg>`;
    style.innerHTML = `* { cursor: url('${flowerSvg}') 12 12, auto !important; }`;
    document.head.appendChild(style);

    window.addEventListener("mousemove", onMouseMove);
    document.documentElement.addEventListener("mouseleave", onMouseLeave);
 
    // Preload all frames so there's no flicker on first cycle
    FRAMES.forEach((src) => { const i = new Image(); i.src = src; });
 
    // Animation loop — advances frame on its own timer, positions on every RAF
    const tick = (timestamp: number) => {
      // Advance frame
      if (lastRef.current === null) lastRef.current = timestamp;
      const elapsed = timestamp - lastRef.current;
      if (elapsed >= FRAME_DURATION) {
        const nextFrame = (frameRef.current + 1) % FRAMES.length;
        if (containerRef.current) {
          const currentImg = containerRef.current.children[frameRef.current] as HTMLElement;
          const nextImg = containerRef.current.children[nextFrame] as HTMLElement;
          if (currentImg && nextImg) {
            currentImg.style.display = "none";
            nextImg.style.display = "block";
          }
        }
        frameRef.current = nextFrame;
        lastRef.current  = timestamp - (elapsed % FRAME_DURATION);
      }
 
      // Update position
      if (containerRef.current) {
        const { x, y } = posRef.current;
        containerRef.current.style.transform =
          `translate(${x - HOT_SPOT_X}px, ${y - HOT_SPOT_Y}px)`;
      }
 
      rafRef.current = requestAnimationFrame(tick);
    };
 
    rafRef.current = requestAnimationFrame(tick);
 
    return () => {
      document.head.removeChild(style);
      window.removeEventListener("mousemove", onMouseMove);
      document.documentElement.removeEventListener("mouseleave", onMouseLeave);
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [onMouseMove, onMouseLeave, isTouchDevice]);
 
  if (isTouchDevice) return null;

  return (
    <div
      ref={containerRef}
      aria-hidden="true"
      style={{
        position:       "fixed",
        top:            0,
        left:           0,
        width:          CURSOR_SIZE,
        height:         CURSOR_SIZE,
        pointerEvents:  "none",
        userSelect:     "none",
        zIndex:         999999,
        opacity:        visible ? 1 : 0,
        willChange:     "transform",
        transform:      "translate(-200px, -200px)",
      }}
    >
      {FRAMES.map((src, index) => (
        <img
          key={index}
          src={src}
          alt=""
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            width: "100%",
            height: "100%",
            imageRendering: "pixelated",
            display: index === 0 ? "block" : "none",
          }}
        />
      ))}
    </div>
  );
}